$ErrorActionPreference = "Stop"

# ============================================================
# CONFIG
# ============================================================

$BaseDir            = "C:\Windows\System32\Acceleron\Appblocker"
$CertDir            = Join-Path $BaseDir "Certificate"

$PolicyScriptPath   = Join-Path $BaseDir "Appblocker.exe"
$JsonPath           = Join-Path $BaseDir "Blocked-apps.json"
$CertPath           = Join-Path $CertDir "GainwellWallpaper.cer"

$PolicyTaskName     = "App Blocker Policy"

$PinnedThumbprint   = "ECACA66CD84B620E80C8329A253DE85149666D6E"

$TriggerInterval    = 5
$IsSystem           = ([Security.Principal.WindowsIdentity]::GetCurrent().IsSystem)
$IsAdmin            = ([Security.Principal.WindowsPrincipal] `
                      [Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)

# ============================================================
# ENSURE BASE DIRECTORY
# ============================================================

# Create base directory if not exists
if (-not (Test-Path $BaseDir)) {
    New-Item -Path $BaseDir -ItemType Directory -Force | Out-Null
}

# Create certificate directory if not exists
if (-not (Test-Path $CertDir)) {
    New-Item -Path $CertDir -ItemType Directory -Force | Out-Null
}

# ============================================================
# CLEAN OLD TASKS (SAFE)
# ============================================================

Get-Process -Name "AppBlocker" -ErrorAction SilentlyContinue | Stop-Process -Force

Get-ScheduledTask $PolicyTaskName -ErrorAction SilentlyContinue | Unregister-ScheduledTask -Confirm:$false
Get-ScheduledTask "BlockAnyDeskTask Policy" -ErrorAction SilentlyContinue | Unregister-ScheduledTask -Confirm:$false

Remove-Item $PolicyScriptPath  -Force -ErrorAction SilentlyContinue
Remove-Item $CertPath -Force -ErrorAction SilentlyContinue
Remove-Item "C:\Windows\Block-Anydesk.ps1" -Force -ErrorAction SilentlyContinue
Remove-Item "C:\Windows\Block-WindowsStore.ps1" -Force -ErrorAction SilentlyContinue
Remove-Item "C:\Windows\RunHidden.vbs" -Force -ErrorAction SilentlyContinue
Remove-Item "C:\Windows\RunHidden-Store.vbs" -Force -ErrorAction SilentlyContinue

# ============================================================
# EMBEDDED BINARIES (BASE64)
# ============================================================

$CertBase64 = @'

'@

$AppBlockerExeBase64 = @'

'@

$JsonContent = @'
{
  "apps": [
    {
      "name": "AnyDesk",
      "blockMessage": "Your Administrator has blocked AnyDesk for security reasons.",
      "matchType": "ProductName",
      "matchValue": "AnyDesk",
      "adminExempt": false
    },
    {
      "name": "Windows Store",
      "blockMessage": "Windows Store has been blocked by your Administrator.",
      "matchType": "ProcessName",
      "matchValue": "WinStore.App",
      "adminExempt": true
    },
    {
      "name": "TeamViewer",
      "blockMessage": "TeamViewer has been blocked by your Administrator.",
      "matchType": "ProductName",
      "matchValue": "TeamViewer",
      "adminExempt": false
    }
  ]
}
'@

# ============================================================
# DECODE EXEs
# ============================================================

$PolicyExeBytes = [Convert]::FromBase64String($AppBlockerExeBase64)

# ============================================================
# WRITE + TRUST CERTIFICATE (SYSTEM ONLY)
# ============================================================

if ($IsSystem -or $IsAdmin) {

    if (-not (Test-Path $CertPath)) {
        [IO.File]::WriteAllBytes(
            $CertPath,
            [Convert]::FromBase64String($CertBase64)
        )
    }

    foreach ($store in @(
        "Root",
        "TrustedPublisher"
    )) {
        if (-not (certutil -store $store | Select-String $PinnedThumbprint)) {
            & certutil.exe -addstore $store $CertPath | Out-Null
        }
    }
}

# ============================================================
# WRITE POLICY SCRIPT (SYSTEM)
# ============================================================
$WritePolicyExe = $true

if (Test-Path $PolicyScriptPath) {

    $Sig = Get-AuthenticodeSignature $PolicyScriptPath

    if (
        $Sig.SignerCertificate -and
        $Sig.SignerCertificate.Thumbprint -eq $PinnedThumbprint
    ) {
        $WritePolicyExe = $false
    }
}

if ($WritePolicyExe) {

    [IO.File]::WriteAllBytes($PolicyScriptPath, $PolicyExeBytes)

    Start-Sleep 2
    $Sig = Get-AuthenticodeSignature $PolicyScriptPath

    if (
        -not $Sig.SignerCertificate -or
        $Sig.SignerCertificate.Thumbprint -ne $PinnedThumbprint -or
        $Sig.Status -in @('HashMismatch','NotSigned')
    ) {
        throw "Appblocker.exe signature validation failed"
    }
}

# ============================================================
# WRITE JSON CONFIG
# ============================================================

Set-Content -Path $JsonPath -Value $JsonContent -Encoding UTF8 -Force

# ============================================================
# SCHEDULED TASK: POLICY (SYSTEM)
# ============================================================

# Define the action to execute the VBScript script
$action = New-ScheduledTaskAction -Execute $PolicyScriptPath

# Create the time-based trigger
$timeTrigger = New-ScheduledTaskTrigger -Once -At (Get-Date).AddMinutes(1)

# Create the logon-based trigger
$logonTrigger = New-ScheduledTaskTrigger -AtLogOn

# Define the task settings
$taskSettings = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -WakeToRun -StartWhenAvailable
$taskSettings.Hidden = $true
$taskSettings.DisallowStartIfOnBatteries = $false
$taskSettings.Priority = 7
$taskSettings.ExecutionTimeLimit = "PT0S"

# Store all triggers in an array
$triggers = @($timeTrigger, $logonTrigger)

# Define the task principal
$taskPrincipal = New-ScheduledTaskPrincipal -GroupId "NT AUTHORITY\INTERACTIVE" -RunLevel Highest

# Register the scheduled task
$null = Register-ScheduledTask -Action $action -Trigger $triggers -TaskName $PolicyTaskName -Settings $taskSettings -Principal $taskPrincipal -Force

Write-Host "App Blocker Policy Updated"